from ragas import evaluate, EvaluationDataset
from ragas.metrics import (
    Faithfulness, AnswerRelevancy, ContextPrecision, ContextRecall,
)

rows = [{
    "user_input": "What is your refund window?",
    "retrieved_contexts": ["Our policy allows refunds within 30 days."],
    "response": "You can get a refund within 30 days of purchase.",
    "reference": "Refunds are available within 30 days.",
}]

dataset = EvaluationDataset.from_list(rows)
result = evaluate(
    dataset=dataset,
    metrics=[Faithfulness(), AnswerRelevancy(),
             ContextPrecision(), ContextRecall()],
)
print(result)  # e.g. {'faithfulness': 1.0, 'answer_relevancy': 0.98, ...}
